using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" in EF 9.
            // Existing 500K documents and direct SQL queries use "Discriminator".
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — JSON "id" no longer contains the discriminator.
            // EF 8 wrote "Product|123"; EF 9 defaults to "123".
            // Re-enable the old composite format so lookups hit existing documents.
            entity.HasDiscriminatorInJsonId();

            // BREAKING CHANGE 3 — HasIndex() now throws for Cosmos (no server-side
            // secondary indexes). The EF 8 call was silently ignored. Removed.
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } = null!; }

