using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous I/O (ToList, SaveChanges, …) now throws
    // InvalidOperationException on the Cosmos provider. All queries must be async.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we kept "Discriminator" as the
        // discriminator property name (see ProductContext).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

